import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Facebook App Install Ads","description":"","frontmatter":{"title":"Facebook App Install Ads","slug":"facebook-app-install-ads"},"headers":[],"relativePath":"marketer-hub/facebook-app-install-ads.md","filePath":"marketer-hub/facebook-app-install-ads.md"}'),r={name:"marketer-hub/facebook-app-install-ads.md"};function s(i,e,c,d,l,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch Links can be used together with Facebook App Install Campaign ads, allowing you to track ad-driven installs on the Branch dashboard and deep link those new users directly to content the first time they open your app.</p><p>Note: This documentation applies for Ad placements across Facebook and the Audience Network.</p><p>This documentation supports the following Facebook Ad Campaign types:</p><table tabindex="0"><thead><tr><th>Facebook Campaign Category</th><th>Campaign Type/Objective</th><th>Branch Ad Format</th></tr></thead><tbody><tr><td>Consideration</td><td>App Installs</td><td>App Only: Install</td></tr></tbody></table><h3 id="facebook-campaign-advert-format-support-table" tabindex="-1">Facebook Campaign Advert Format Support Table <a class="header-anchor" href="#facebook-campaign-advert-format-support-table" aria-label="Permalink to &quot;Facebook Campaign Advert Format Support Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Facebook Campaign Type</th><th>Photo</th><th>Video</th><th>Carousel</th><th>Slideshow</th><th>Collection</th><th>Dynamic</th><th>Canvas</th></tr></thead><tbody><tr><td>App Installs</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>-</td><td>-</td><td>✔︎</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Facebook Campaign Types</p><p>Looking for other Facebook Ad campaign types? Please check out our <a href="./facebook-ads-overview.html">Facebook Ads Overview guide</a>.</p></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><ul><li><p>To track installs from Facebook Ads you should <a href="./ios-basic-integration.html">integrate the Branch SDK</a> into your app.</p></li><li><p>To use Branch Links in Facebook App Install Ads ensure you have:</p><ul><li>URI schemes configured on iOS</li><li>URI schemes configured on Android</li><li>iOS App Store ID set</li><li>Android Package Name set</li><li>Social Media Settings filled out (i.e. OG tags at the bottom of <a href="./configure-default-link-behaviors.html#4-social-media-preview">Link Settings</a>)</li></ul></li><li><p>If you want to deep link from your ads directly to content, you should <a href="./in-app-routing.html">configure deep link routing</a>.</p></li><li><p>Ads is a premium product priced on Monthly Active Users. Sign up for the Ads product to enable this functionality.</p></li></ul></div><h3 id="enable-facebook-as-an-ad-partner-for-measurement" tabindex="-1">Enable Facebook as an Ad Partner (for measurement) <a class="header-anchor" href="#enable-facebook-as-an-ad-partner-for-measurement" aria-label="Permalink to &quot;Enable Facebook as an Ad Partner (for measurement)&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Enable Facebook as an Ad Partner</p><p>Completing this section -- <strong>Enable Facebook as an Ad Partner</strong> -- will result in Branch sending app events to Facebook in order to attribute them back to ad campaigns. <strong>This does not enable deep linking for the ad</strong>. Further work below is required for deep linking.</p></div><p>If you haven&#39;t enabled Facebook as an Ad Partner on the Branch dashboard follow this section to do so. Advanced options for sending events can be found <a href="./facebook-faq-and-advanced-options.html#facebook-ads-advanced-options">here</a>.</p><ol><li><p>Navigate to the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management tab</a>.</p></li><li><p>Search for <strong>Facebook</strong>.</p></li><li><p>Click <strong>Connect With Facebook</strong></p></li><li><p>Log in to Facebook if you are not logged in</p></li><li><p>Confirm that Branch can receive your public profile</p></li><li><p>Confirm that Branch can have permissions <code>ads_read</code>, which is used to surface impressions and clicks on the Branch Dashboard.</p></li><li><p>Select the ad accounts for which you want to run app install ads or app engagement ads</p></li><li><p>Click to select a Facebook app id for which you want to run Facebook ads. <em>(Note - To Enable OS specific FB app IDs, please reach out to Branch support</em> <a href="mailto:support@branch.io" target="_blank" rel="noreferrer"><em>support@branch.io</em></a><em>)</em></p></li></ol><p><em>[Image: 1136]</em></p><ol start="9"><li><p>Copy the app id</p></li><li><p>Paste the app id and press <code>Save</code></p></li></ol><p>Add your Facebook App Secret to enable deferred deep linking.</p><ol start="11"><li><p>Facebook is now enabled as an ad partner! Note that if you have different attribution windows between Facebook and Branch, those will be highlighted. The warning has a link to the docs on how to align these attribution windows.</p></li><li><p><strong>(Optional) Add System User Token</strong>: By default, Branch uses the authenticated user’s token to retrieve data from Facebook. However, you can optionally configure a System User Token instead.</p><p>A System User Token is tied to your Facebook Business Manager rather than an individual user account, so it typically lasts longer and won’t expire if a team member leaves. This provides more stable, long-term access for data retrieval. There is meant to be only one system user, and the rest of the team uses the same System User Token for access.</p><p><strong>Important</strong>: Only admins can perform the steps required to generate a System User Token. Once your token is generated, keep it secure and do not share it outside your trusted team.</p><p><strong>Create a System User Token in Meta</strong></p><ol><li>Log in to Meta Business Suite and navigate to Business Settings.</li><li>Under <strong>Users</strong>, select <strong>System Users</strong>, then select <strong>Add New System User</strong>. Enter a name and assign the Admin role.</li><li>Select the new system user’s name, then <strong>Assign Assets</strong>. Select your app and grant the <strong>Manage App</strong> permission. If needed, also add your ad account and grant <strong>Manage Ad Account</strong> permissions.</li><li>With the system user selected, select <strong>Generate New Token</strong>. Choose your app and select the required permissions (e.g., <code>business_management</code> , <code>ads_management</code>).</li><li>Select <strong>Generate Token</strong> and securely save the access token.</li></ol><p><strong>Add the System User Token in Branch</strong></p><ol><li>On the <strong>Account Settings</strong> tab for Facebook’s ad partner settings in Branch, locate the <strong>System User Token</strong> field.</li><li>Paste your token and select <strong>Save</strong>.</li></ol></li><li><p><strong>(Optional) Create a Facebook Ads link for deep linking</strong>: Select the <strong>Create Facebook Link</strong> button in the top right hand corner. Scroll down to the section on <strong>Deep link your app install campaign</strong> for more details.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Connecting Multiple Accounts</p><p>All SANs - including Facebook - accept multiple accounts. However, only a single Branch user can authenticate the integration. This means that the single user must have access to all of the accounts you wish to connect.</p><p><strong>Note:</strong> Do not authenticate a single ad account to multiple Branch apps (ex. Live and Test apps) as that will cause issues with authentication and Dashboard reports.</p><p>If you are having trouble finding or selecting the ad account(s) for which you want to run ads, please visit our <a href="./facebook-faq-and-advanced-options.html">FAQ</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">Agency-Managed Campaigns</p><ul><li>If an Agency manages your Facebook Ads campaigns, please see <a href="./what-is-a-self-attributing-network.html#agency-managed-san-campaigns">Agency-managed SAN Campaigns</a>.</li></ul></div><h2 id="branch-facebook-field-mappings" tabindex="-1">Branch &lt;&gt; Facebook Field Mappings <a class="header-anchor" href="#branch-facebook-field-mappings" aria-label="Permalink to &quot;Branch &lt;&gt; Facebook Field Mappings&quot;">​</a></h2><p>Branch maps the following data fields from Facebook App Install Ads to Branch.</p><table tabindex="0"><thead><tr><th>Facebook Data</th><th>Branch Data</th><th>Possible Values</th></tr></thead><tbody><tr><td>n/a</td><td><code>~advertising_partner_name</code></td><td>“Facebook”</td></tr><tr><td>n/a</td><td><code>~channel</code></td><td>“Facebook” if null or last touch</td></tr><tr><td>n/a</td><td><code>~feature</code></td><td>&quot;Paid Advertising&quot;</td></tr><tr><td><code>campaign_name</code></td><td><code>~campaign</code></td><td>Light Bright Launch</td></tr><tr><td><code>campaign_id</code></td><td><code>~campaign_id</code></td><td>15292426</td></tr><tr><td><code>publisher_platform</code></td><td><code>~secondary_publisher</code></td><td>facebook / instagram / audience_network</td></tr><tr><td><code>creative_name</code></td><td><code>~creative_name</code></td><td>Light Bright Vertical</td></tr><tr><td><code>creative_id</code></td><td><code>~creative_id</code></td><td>1234567890</td></tr><tr><td><code>ad_set_name</code></td><td><code>~ad_set_name</code></td><td>Light Bright</td></tr><tr><td><code>ad_set_id</code></td><td><code>~ad_set_id</code></td><td>12345567890</td></tr><tr><td><code>ad_name</code></td><td><code>~ad_name</code></td><td>Light Bright</td></tr><tr><td><code>ad_id</code></td><td><code>~ad_id</code></td><td>123456789</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Cost Data Support</p><ul><li>To view the cost metrics Branch provides, please see <a href="./what-is-a-self-attributing-network.html#san-cost-data">SAN Cost Data</a>.</li><li>If you&#39;re seeing discrepancies, please see <a href="./common-sources-of-san-reporting-discrepancies.html">Common Sources of SAN Reporting Discrepancies</a>.</li></ul></div><h3 id="view-your-data" tabindex="-1">View Your Data <a class="header-anchor" href="#view-your-data" aria-label="Permalink to &quot;View Your Data&quot;">​</a></h3><p>The <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics Page</a> on the Branch dashboard provides an interactive time series graph and table to view the performance of your Ad campaigns.</p><p>The table shows summary data on the performance of each Ad campaign. On the right top side of the table you can find a <strong>download button</strong> to retrieve the chart&#39;s content as a CSV file.</p><div class="info custom-block"><p class="custom-block-title">Interacting with your data</p><p>Breakdown and compare aspects of your Ad campaigns&#39; performance by using the <code>Compare by +</code> button to add a parameter to split the data displayed data by.</p></div><p>Then use the <code>and +</code> button to refine the data displayed to gain deeper insight into the performance of your Ad campaigns.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>We now have a dedicated <a href="./facebook-faq-and-advanced-options.html">FAQ page for Facebook app ads</a>. If you are having any issues with app ads, please review the FAQ.</p><p>If you are having issues with web-only ads, you can check out the FAQ.</p><h5 id="branch-cost-data-not-matching-the-ad-partner-dashboard" tabindex="-1">Branch Cost data not matching the Ad Partner dashboard <a class="header-anchor" href="#branch-cost-data-not-matching-the-ad-partner-dashboard" aria-label="Permalink to &quot;Branch Cost data not matching the Ad Partner dashboard&quot;">​</a></h5><p>Please ensure that you&#39;ve selected the same time zone in your Ad Partner&#39;s dashboard and your Branch dashboard.</p><h5 id="cpi-metric-doesn-t-match-between-ad-partner-and-branch-although-cost-metric-does" tabindex="-1">CPI metric doesn&#39;t match between Ad Partner and Branch, although cost metric does <a class="header-anchor" href="#cpi-metric-doesn-t-match-between-ad-partner-and-branch-although-cost-metric-does" aria-label="Permalink to &quot;CPI metric doesn&#39;t match between Ad Partner and Branch, although cost metric does&quot;">​</a></h5><p>Branch&#39;s last-click attribution model can lead to differences in install counts for Branch vs self-attributing networks (SANs) that in turn cause differences in CPI metrics. Verify whether your cost and install metrics match the Ad Partner&#39;s dashboard. If there is an install discrepancy, it is likely legitimate and due to differences in install counts, where Branch&#39;s number is more accurate. If the discrepancy is very large, investigate causes of install discrepancies through the usual troubleshooting steps.</p><h5 id="cost-click-and-impression-data-is-all-missing" tabindex="-1">Cost, click and impression data is all missing <a class="header-anchor" href="#cost-click-and-impression-data-is-all-missing" aria-label="Permalink to &quot;Cost, click and impression data is all missing&quot;">​</a></h5><p>Generally, reauthenticating a partner and waiting 24 hours will re-enable cost data.</p><p>When you reauthenticate, double check that you have selected the correct accounts. We will only pull cost data for accounts that you select as part of the authentication process.</p><p>Background:<br> Cost, click and impression data for SANs are generally sourced from Partner APIs (unless Branch impression pixels or links are being intentionally used for attribution, for example, in web campaigns). When you enable a SAN, you authenticate with your provider. Branch uses this authentication to retrieve click, cost and impression data. If the authentication token expires (for example, if you reset your password, or the partner force resets your token), then you may not see click, impression or cost data. In this case, simply reauthenticate and that will refresh your token.</p><h5 id="cost-data-is-missing-or-incorrect-for-certain-compare-by-breakdowns" tabindex="-1">Cost data is missing or incorrect for certain &quot;compare by&quot; breakdowns <a class="header-anchor" href="#cost-data-is-missing-or-incorrect-for-certain-compare-by-breakdowns" aria-label="Permalink to &quot;Cost data is missing or incorrect for certain &quot;compare by&quot; breakdowns&quot;">​</a></h5><p>Downstream events, such as <em>installs</em>, should always have the full range of compare by options in the dashboard. However, <em>clicks, impressions and cost</em> data for SAN are often imported via Partner APIs. These APIs do not necessarily provide the same breakdowns for cost data that Branch supports with raw install events, so there may be cases where the Branch Dashboard cannot compare by the same dimensions for cost data vs install data.</p><h3 id="troubleshooting-deep-linking" tabindex="-1">Troubleshooting deep linking <a class="header-anchor" href="#troubleshooting-deep-linking" aria-label="Permalink to &quot;Troubleshooting deep linking&quot;">​</a></h3><h5 id="intercepting-deep-links-before-branch" tabindex="-1">Intercepting Deep Links Before Branch <a class="header-anchor" href="#intercepting-deep-links-before-branch" aria-label="Permalink to &quot;Intercepting Deep Links Before Branch&quot;">​</a></h5><p>If you use Branch deep links in Facebook app ads, please check the following.</p><p>We recently discovered an issue where an app was calling Facebook&#39;s SDK to fetch the deferred app link within their iOS and Android app. Branch calls use this same mechanism via direct API integration, but if Facebook&#39;s SDK retrieves it before we do, Branch will not see any deep link data. Please ensure to comment out any calls to the following API within your app:</p><ul><li><a href="https://developers.facebook.com/docs/reference/android/current/class/AppLinkData/" target="_blank" rel="noreferrer">Android: fetchDeferredAppLink</a></li><li><a href="https://developers.facebook.com/docs/reference/ios/current/class/FBSDKAppLinkUtility/" target="_blank" rel="noreferrer">iOS: fetchDeferredAppLink</a></li></ul><h5 id="issues-reading-facebook-app-links" tabindex="-1">Issues Reading Facebook App Links <a class="header-anchor" href="#issues-reading-facebook-app-links" aria-label="Permalink to &quot;Issues Reading Facebook App Links&quot;">​</a></h5><p>If Facebook is having trouble reading the App Links from the Branch Link, you might see messages like these while trying to test out the flow. This means that there is something corrupted in the OG tags causing Facebook to not parse your link.</p><p><strong>Rescrape the OG Tags</strong></p><p>You can test the OG tags using the <a href="https://developers.facebook.com/tools/debug" target="_blank" rel="noreferrer">Sharing Debugger tool</a> provided by Facebook:</p><ol><li>Paste the Branch Link into the Input URL box.</li><li>Click on the Show existing scrape information button.</li><li>Examine errors regarding App Links from the output window.</li><li>Click on the Fetch New Scrape Information button. This last step typically resolves this problem if you are certain that your Branch Link Settings are correct.</li></ol><div class="info custom-block"><p class="custom-block-title">Automate Rescraping Process</p><p>You can further automate the rescraping process by using this command after you create a new link and before you use it for any ads:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --insecure &quot;https://graph.facebook.com/?id=[YOUR-URL-TO-SCRAPE]&amp;scrape=true&quot;</span></span></code></pre></div></div><p><strong>If the OG tag tester continues to report problems</strong></p><ol><li><p>Examine your <a href="https://dashboard.branch.io/#/settings/link" target="_blank" rel="noreferrer">Link Settings</a> and ensure that for all platforms (for which an app is available), that a URI scheme and a link to the app in the Play/App Store is configured. If you are using a Custom URL for your iOS Redirect, then you need to append <code>?id[10-digit App Store ID]</code> to the URL. This is necessary in order to fully generate the App Links and OG tags that the Facebook scraper expects to find.</p><ul><li>For example, if your App Store URL is <code>https://itunes.apple.com/us/app/my-app-name/id1234567890</code>, then your Custom URL value should be <code>https://example.com?id1234567890</code></li></ul></li><li><p>If errors from the output window pertain to OG tags i.e. missing title, description etc. then examine link OG tags by appending <code>?debug=true</code>.</p></li><li><p>If you haven&#39;t set OG tags on a per link level, then please check your Dashboard&#39;s global Social Media Display Customization settings from the <a href="https://dashboard.branch.io/#/settings/link" target="_blank" rel="noreferrer">Link Settings</a> page.</p></li></ol><p><strong>Use a direct deep link</strong></p><p>As a last resort, you can manually input a direct deep link. To retrieve this:</p><ol><li>Go to Facebook&#39;s <a href="https://developers.facebook.com/tools/debug/" target="_blank" rel="noreferrer">Open Graph Object Debugger</a></li><li>Input the Branch Link you want to use for your ad</li><li>Click <strong>Fetch new scrape information</strong></li><li>Find the <code>al:ios:url</code> line (it should look like )</li><li>Copy the value of this (<code>myapp://open?link_click_id=link-242052337263342024</code>) and input it as the Deep Link value of your ad</li></ol><p>If none of these approaches work, please reach out to our <a href="./submit-a-ticket.html">support team</a> immediately.</p><h5 id="known-issue-with-app-restrictions" tabindex="-1">Known Issue with App Restrictions <a class="header-anchor" href="#known-issue-with-app-restrictions" aria-label="Permalink to &quot;Known Issue with App Restrictions&quot;">​</a></h5><p>We recently discovered a bug within the Facebook system that prevents App Links from being read by the robot if you change any of these values from the defaults in your Advanced Facebook App Settings tab. Please make sure</p><ul><li>Contains Alcohol is set to <strong>No</strong></li><li>Age Restriction is set to <strong>Anyone (13+)</strong></li><li>Social Discovery is set to <strong>Yes</strong></li><li>Country Restricted is set to <strong>No</strong></li></ul><p>It has to look like this <strong>exactly</strong>:</p>',63)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
